            return NotImplemented
        if op == 2:
            return self.intervals.equal(other.intervals)
        return NotImplemented

    def __req__(DateMap self, other):
        if other.__class__ is not DateMap:
            return NotImplemented
        return other.__eq__(self)

    def __contains__(DateMap self, date date):
